const category = env.get('category_name');
const results = Array.isArray(msg.payload) ? msg.payload : [];

const colorFor = status => {
    if (status === 'PASS') return 'green';
    if (status === 'FAIL') return 'red';
    if (status === 'MISCONFIGURED' || status === 'CATALOG_MISS') return 'orange';
    return 'grey';
};

const subtitleFor = item => {
    if (item.measured_v !== undefined) {
        return `${item.measured_v}V (expected ${item.expected_v}±${item.tolerance_v})`;
    }
    if (item.measured_hz !== undefined) {
        return `${item.measured_hz}Hz (target ${item.target_hz}±${item.tolerance_hz})`;
    }
    if (item.detected_devices !== undefined) {
        return `${item.detected_devices}/${item.expected_devices} devices detected`;
    }
    return '';
};

const nameFor = item =>
    item.relay_name || item.input_name || item.output_name ||
    item.control_name || item.name || item.id || 'unnamed';

let pass = 0, fail = 0;
const items = results.map(r => {
    const status = r.status || 'UNKNOWN';
    if (status === 'PASS') pass++;
    else fail++;
    return {
        id: nameFor(r),
        status,
        color: colorFor(status),
        subtitle: subtitleFor(r),
        error: r.error
    };
});

msg.payload = {
    category,
    items,
    counts: { pass, fail, total: results.length },
    timestamp: new Date().toISOString()
};
return msg;
